<!DOCTYPE html>
<html>
<head>
  <title>2048</title>
  <style>
    body {
      background-color: #1e1e1e;
      color: #eee;
      font-family: monospace;
      text-align: center;
    }

    #board {
      display: flex;
      justify-content: center;
      margin: 20px auto;
    }

    .tile {
      width: 30px;
      height: 30px;
      border: 1px solid #555;
      font-size: 24px;
      text-align: center;
      line-height: 30px;
    }

    .tile.empty {
      background-color: #333;
    }

    .tile.two {
      background-color: #336699;
    }

    .tile.four {
      background-color: #4499bb;
    }

    .tile.eight {
      background-color: #55bb77;
    }

    .tile.sixteen {
      background-color: #66cc99;
    }

    #score {
      margin-top: 20px;
      font-size: 20px;
    }

    #reset {
      padding: 10px 20px;
      background-color: #555;
      color: #eee;
      border: none;
      cursor: pointer;
      font-size: 16px;
    }
  </style>
</head>
<body>
  <h1>2048</h1>
  <div id="board"></div>
  <div id="score">Score: 0</div>
  <button id="reset">Start New Game</button>

  <script>
    const size = 4;
    let board = [];
    let score = 0;
    let newTileCount = 2;

    function initBoard() {
      board = Array(size).fill(null).map(() => Array(size).fill(0));
      spawnNewTile();
      spawnNewTile();
      updateBoardDisplay();
      updateScoreDisplay();
    }

    function spawnNewTile() {
      let emptyCells = [];
      for (let i = 0; i < size; i++) {
        for (let j = 0; j < size; j++) {
          if (board[i][j] === 0) {
            emptyCells.push([i, j]);
          }
        }
      }

      if (emptyCells.length > 0) {
        const randomIndex = Math.floor(Math.random() * emptyCells.length);
        const [row, col] = emptyCells[randomIndex];
        board[row][col] = Math.random() < 0.9 ? 2 : 4;
      }
    }

    function move(direction) {
      let moved = false;
      switch (direction) {
        case 'left':
          for (let i = 0; i < size; i++) {
            moved |= slideAndMerge(i, 0);
          }
          break;
        case 'right':
          for (let i = 0; i < size; i++) {
            moved |= slideAndMerge(i, size - 1);
          }
          break;
        case 'up':
          for (let j = 0; j < size; j++) {
            moved |= slideAndMerge(0, j);
          }
          break;
        case 'down':
          for (let j = 0; j < size; j++) {
            moved |= slideAndMerge(size - 1, j);
          }
          break;
      }

      if (moved) {
        spawnNewTile();
      }
      return moved;
    }

    function slideAndMerge(row, col) {
      let changed = false;
      for (let i = 0; i < size; i++) {
        const currentCell = board[row][i];
        if (currentCell !== 0) {
          let j = i;
          while (j > 0 && board[row][j - 1] === 0) {
            board[row][j - 1] = currentCell;
            board[row][j] = 0;
            changed = true;
            j--;
          }

          if (j > 0 && board[row][j - 1] === currentCell) {
            board[row][j - 1] *= 2;
            board[row][j] = 0;
            score += board[row][j - 1];
            changed = true;
          }
        }
      }
      return changed;
    }

    function boardToString() {
      return board.map(row => row.join(' ')).join('');
    }

    function updateBoardDisplay() {
      const boardDiv = document.getElementById('board');
      boardDiv.innerHTML = '';
      for (let i = 0; i < size; i++) {
        for (let j = 0; j < size; j++) {
          const tile = document.createElement('div');
          tile.classList.add('tile');
          if (board[i][j] === 0) {
            tile.classList.add('empty');
          } else if (board[i][j] === 2) {
            tile.classList.add('two');
          } else if (board[i][j] === 4) {
            tile.classList.add('four');
          } else if (board[i][j] === 8) {
            tile.classList.add('eight');
          } else if (board[i][j] === 16) {
            tile.classList.add('sixteen');
          }
          tile.textContent = board[i][j];
          boardDiv.appendChild(tile);
        }
      }
    }

    function updateScoreDisplay() {
      const scoreDiv = document.getElementById('score');
      scoreDiv.textContent = `Score: ${score}`;
    }

    window.game = {
      size: size,
      reset: () => {
        initBoard();
      },
      move: (direction) => move(direction),
      board: () => board,
      setBoard: (arr) => {
        board = arr;
        updateBoardDisplay();
      },
      score: () => score,
    };

    document.addEventListener('keydown', (event) => {
      if (event.key === 'ArrowLeft') {
        game.move('left');
      } else if (event.key === 'ArrowRight') {
        game.move('right');
      } else if (event.key === 'ArrowUp') {
        game.move('up');
      } else if (event.key === 'ArrowDown') {
        game.move('down');
      }
    });

    document.getElementById('reset').addEventListener('click', game.reset);

    initBoard();
  </script>
</body>
</html>
